import { motion } from "motion/react";

export function GlitchOverlay() {
    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 pointer-events-none overflow-hidden"
        >
            {/* Noise Overlay */}
            <div className="absolute inset-0 bg-repeat opacity-[0.15] mix-blend-overlay w-full h-full pointer-events-none z-10"
                style={{ backgroundImage: "url('data:image/svg+xml;base64,')" }}
            />

            {/* Chromatic Aberration & Shake */}
            <div className="absolute inset-0 bg-background/90 mix-blend-hard-light animate-glitch" />

            {/* Scanlines */}
            <div className="absolute inset-0 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_4px,3px_1px] pointer-events-none z-20" />
        </motion.div>
    );
}
